  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">El marco SB16 / SB18 / SB19 de Delaware</text>
    <g font-family="sans-serif" font-size="13">
      <rect x="30" y="55" width="640" height="66" rx="8" fill="rgba(56,189,248,.10)" stroke="#38bdf8"/>
      <text x="50" y="80" fill="#7dd3fc" font-weight="700">SB16 — Ley de Modernización Bancaria</text>
      <text x="50" y="102" fill="#a1a1aa" font-size="12">Nuevas definiciones legales de "activo digital / moneda virtual"; base de custodia fiduciaria</text>
      <rect x="30" y="131" width="640" height="66" rx="8" fill="rgba(34,197,94,.10)" stroke="#22c55e"/>
      <text x="50" y="156" fill="#4ade80" font-weight="700">SB18 — Ley de Transmisión de Dinero y Moneda Virtual</text>
      <text x="50" y="178" fill="#a1a1aa" font-size="12">Licencias y supervisión continua para transmisores de dinero y firmas de moneda virtual</text>
      <rect x="30" y="207" width="640" height="90" rx="8" fill="rgba(250,204,21,.10)" stroke="#facc15"/>
